import React, { useState, useEffect } from 'react';
import { Link, useSearchParams } from 'react-router-dom';

const SearchResults = () => {
  const [allTours, setAllTours] = useState([]);
  const [tours, setTours] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchParams] = useSearchParams();

  const filterTours = (allTours) => {
    console.log('🔍 === ДИАГНОСТИКА ===');
    console.log('URL параметры:', Object.fromEntries(searchParams));
    
    let filtered = [...allTours];
    const decodeParam = (param) => decodeURIComponent(param || '');

    // 1. СТРАНА - ПОДРОБНЫЙ ЛОГ
    const country = decodeParam(searchParams.get('country'));
    console.log('🌍 Ищем страну:', `"${country}"`);
    console.log('Все страны в турах:', allTours.map(t => t.country));
    
    if (country) {
      filtered = filtered.filter(tour => {
        const match = tour.country === country;
        console.log(`  ${tour.title.padEnd(30)} | "${tour.country}" ${match ? '✅' : '❌'} "${country}"`);
        return match;
      });
    }

    // 2. ВЫЛЕТ - ПОДРОБНЫЙ ЛОГ
    const departure = decodeParam(searchParams.get('departure'));
    console.log('✈️ Ищем вылет:', `"${departure}"`);
    console.log('Все города вылета:', allTours.map(t => t.departureCity));
    
    if (departure) {
      filtered = filtered.filter(tour => {
        const match = tour.departureCity === departure;
        console.log(`  ${tour.title.padEnd(30)} | "${tour.departureCity}" ${match ? '✅' : '❌'} "${departure}"`);
        return match;
      });
    }

    console.log('🎯 ИТОГО:', filtered.length);
    return filtered;
  };

  useEffect(() => {
    console.log('📦 Загружаем tours.json...');
    fetch('tours.json')
      .then(res => {
        console.log('HTTP статус:', res.status);
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        return res.json();
      })
      .then(data => {
        console.log('✅ tours.json загружен:', data.length, 'туров');
        console.log('ПЕРВЫЙ тур:', data[0]);
        setAllTours(data);
        setLoading(false);
      })
      .catch(err => {
        console.error('❌ tours.json ОШИБКА:', err);
        setLoading(false);
      });
  }, []);

  useEffect(() => {
    if (allTours.length > 0) {
      const filtered = filterTours(allTours);
      setTours(filtered);
    }
  }, [searchParams, allTours]);

  if (loading) {
    return <div style={{padding: '40px', textAlign: 'center'}}>Загрузка tours.json...</div>;
  }

  return (
    <div style={{ margin: "0 auto", maxWidth: "1296px", padding: '20px' }}>
      <div style={{ 
        padding: '20px', 
        background: '#ffebee', 
        borderRadius: '8px',
        marginBottom: '20px',
        fontFamily: 'monospace'
      }}>
        <strong>🔍 ДИАГНОСТИКА:</strong><br/>
        Всего туров: {allTours.length} | Найдено: {tours.length}<br/>
        <strong>URL:</strong> <code>{window.location.search}</code><br/>
        <strong>Страна:</strong> "{decodeURIComponent(searchParams.get('country') || 'все')}"<br/>
        <strong>Вылет:</strong> "{decodeURIComponent(searchParams.get('departure') || 'все')}"<br/><br/>
        <button 
          onClick={() => filterTours(allTours)}
          style={{padding: '8px 16px', background: '#c50076', color: 'white', border: 'none', borderRadius: '4px'}}
        >
          🔄 Повторить фильтрацию (Console)
        </button>
      </div>

      {tours.length === 0 ? (
        <div style={{padding: '60px', textAlign: 'center', color: '#666'}}>
          ❌ Туры не найдены
          <div style={{fontSize: '14px', marginTop: '20px'}}>
            F12 → Console → смотри подробные логи!<br/>
            Проверь: 1) tours.json в public/ 2) точные названия полей
          </div>
        </div>
      ) : (
        tours.map(tour => (
          <div key={tour.id} style={{
            border: '1px solid #ddd', borderRadius: '12px', padding: '20px', marginBottom: '20px'
          }}>
            <h3>{tour.title}</h3>
            <p>🌍 {tour.country} | ✈️ {tour.departureCity}</p>
            <p>📅 {tour.dates} | {tour.nights}</p>
            <p><strong style={{color: '#c50076'}}>{tour.price.toLocaleString()} ₽</strong></p>
          </div>
        ))
      )}
    </div>
  );
};

export default SearchResults;
